import React from 'react';
import { BrowserRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { LayoutDashboard, Users, FileText, Search, CreditCard, ClipboardList, Shield } from 'lucide-react';
import Dashboard from './pages/Dashboard';
import History from './pages/History';
import Investigate from './pages/Investigate';

function Sidebar() {
  const location = useLocation();
  const path = location.pathname;

  return (
    <div className="sidebar">
      <div className="nav-logo">
        <Shield size={24} />
      </div>

      <Link to="/" className={`nav-item ${path === '/' ? 'active' : ''}`} title="Dashboard">
        <LayoutDashboard size={20} />
      </Link>

      <Link to="/history" className={`nav-item ${path === '/history' ? 'active' : ''}`} title="History">
        <ClipboardList size={20} />
      </Link>

      <Link to="/investigate" className={`nav-item ${path === '/investigate' ? 'active' : ''}`} title="Investigate">
        <Search size={20} />
      </Link>

      <Link to="/cards" className={`nav-item ${path === '/cards' ? 'active' : ''}`} title="Cards">
        <CreditCard size={20} />
      </Link>

      <Link to="/reports" className={`nav-item ${path === '/reports' ? 'active' : ''}`} title="Reports">
        <FileText size={20} />
      </Link>
    </div>
  );
}

function Topbar() {
  return (
    <div className="topbar">
      <div className="topbar-brand">
        <div className="brand-title">CLEARTRACE</div>
        <div className="brand-sub">AI INVESTIGATION<br />SYSTEM</div>
      </div>
      <div className="topbar-right">
        <div className="status-indicator">
          <div className="status-dot"></div>
          SYSTEM<br />ONLINE
        </div>
        <div style={{ height: '30px', width: '1px', backgroundColor: '#eee', margin: '0 10px' }}></div>
        <div className="officer-info">
          Officer: <span className="officer-name">R. MEHTA</span>
          <div className="officer-avatar">R</div>
        </div>
      </div>
    </div>
  );
}

function App() {
  return (
    <BrowserRouter>
      <div id="root">
        <Sidebar />
        <div className="main-content">
          <Topbar />
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/history" element={<History />} />
            <Route path="/investigate" element={<Investigate />} />
            <Route path="*" element={<div style={{ padding: '40px' }}>Under Construction</div>} />
          </Routes>
        </div>
      </div>
    </BrowserRouter>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Chart as ChartJS, CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend, ArcElement } from 'chart.js';
import { Bar, Doughnut } from 'react-chartjs-2';

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend, ArcElement);

export default function Dashboard() {
    const [loading, setLoading] = useState(true);
    const [stats, setStats] = useState({
        customers: 0,
        txns: 0,
        merchants: 0,
        total_vol: 0,
        avg_txn: 0,
        flagged: 0,
        risk_level_counts: { CRITICAL: 0, HIGH: 0, MEDIUM: 0, LOW: 0 },
        anomaly_type_counts: {}
    });

    useEffect(() => {
        fetch('/api/dashboard/stats')
            .then(r => r.json())
            .then(data => {
                setStats(data);
                setLoading(false);
            })
            .catch(e => {
                console.error('Failed to load stats:', e);
                setLoading(false);
            });
    }, []);

    if (loading) return <div style={{ padding: '40px' }}>Loading real-time data...</div>;

    return (
        <div className="dashboard">
            <div className="page-header">
                <div className="page-title">Investigation Dashboard</div>
                <div className="page-subtitle">REAL-TIME OVERVIEW ΓÇó {new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }).toUpperCase()}</div>
            </div>

            <div className="kpi-row">
                <div className="kpi-card critical">
                    <div className="kpi-card-title">Total Flagged</div>
                    <div className="kpi-value">{stats.flagged}</div>
                    <div className="kpi-trend">Γåæ Flagged transactions</div>
                    <div className="kpi-bg-icon">ΓÜæ</div>
                </div>

                <div className="kpi-card critical">
                    <div className="kpi-card-title">Critical Risk</div>
                    <div className="kpi-value">{stats.risk_level_counts.CRITICAL || 0}</div>
                    <div className="kpi-trend">Requires immediate action</div>
                    <div className="kpi-bg-icon">ΓÜá</div>
                </div>

                <div className="kpi-card review">
                    <div className="kpi-card-title">Under Review</div>
                    <div className="kpi-value">{stats.risk_level_counts.HIGH || 0}</div>
                    <div className="kpi-trend">AI analysis recommended</div>
                    <div className="kpi-bg-icon">ΓÅ│</div>
                </div>

                <div className="kpi-card resolved">
                    <div className="kpi-card-title">Active Connections</div>
                    <div className="kpi-value">{stats.customers}</div>
                    <div className="kpi-trend">Network nodes monitored</div>
                    <div className="kpi-bg-icon">Γ£ô</div>
                </div>
            </div>

            <div className="chart-row">
                <div className="chart-card">
                    <div className="chart-card-title">Flagged Anomalies</div>
                    <div className="chart-container">
                        <Bar
                            data={{
                                labels: Object.keys(stats.anomaly_type_counts || {}).slice(0, 7) || ['None'],
                                datasets: [{
                                    data: Object.values(stats.anomaly_type_counts || {}).slice(0, 7) || [0],
                                    backgroundColor: '#ea7f85', // lighter red
                                    hoverBackgroundColor: '#8b0000', // dark red
                                    borderRadius: 4
                                }]
                            }}
                            options={{
                                responsive: true,
                                maintainAspectRatio: false,
                                plugins: { legend: { display: false } },
                                scales: {
                                    x: { grid: { display: false } },
                                    y: { grid: { color: 'rgba(201, 0, 0, 0.05)' } }
                                }
                            }}
                        />
                    </div>
                </div>

                <div className="chart-card">
                    <div className="chart-card-title">Risk Distribution</div>
                    <div className="chart-container" style={{ position: 'relative' }}>
                        <Doughnut
                            data={{
                                labels: ['Critical', 'High', 'Medium', 'Low'],
                                datasets: [{
                                    data: [
                                        stats.risk_level_counts.CRITICAL || 0,
                                        stats.risk_level_counts.HIGH || 0,
                                        stats.risk_level_counts.MEDIUM || 0,
                                        stats.risk_level_counts.LOW || 0
                                    ],
                                    backgroundColor: ['#8b0000', '#c90000', '#ff6b6b', '#22c55e'],
                                    borderWidth: 0
                                }]
                            }}
                            options={{
                                responsive: true,
                                maintainAspectRatio: false,
                                cutout: '65%',
                                plugins: {
                                    legend: { position: 'right', labels: { usePointStyle: true, padding: 20 } }
                                }
                            }}
                        />
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

export default function History() {
    const [profiles, setProfiles] = useState([]);
    const [loading, setLoading] = useState(true);
    const navigate = useNavigate();

    useEffect(() => {
        fetch('/api/analytics/overview')
            .then(res => res.json())
            .then(data => {
                setProfiles(data.customer_profiles || []);
                setLoading(false);
            })
            .catch(e => {
                console.error(e);
                setLoading(false);
            });
    }, []);

    const formatCurrency = (n) => {
        return 'Rs. ' + Math.round(n).toLocaleString('en-IN');
    };

    return (
        <div className="dashboard">
            <div className="page-header">
                <div className="page-title">Flagged Customer History</div>
                <div className="page-subtitle">COMPREHENSIVE ACTIVITY LOG ΓÇó {profiles.length} RECORDS</div>
            </div>

            <div className="table-card" style={{ background: 'white', borderRadius: '12px', border: '1px solid var(--light-red)', padding: '24px' }}>
                {loading ? (
                    <div>Loading history...</div>
                ) : (
                    <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
                        <thead>
                            <tr style={{ borderBottom: '2px solid var(--light-red)', color: 'var(--text-dim)', fontSize: '11px', textTransform: 'uppercase', fontFamily: '"JetBrains Mono", monospace' }}>
                                <th style={{ padding: '12px 8px' }}>Name / ID</th>
                                <th>Bank</th>
                                <th>Location</th>
                                <th>Total Spent</th>
                                <th>Anomalies</th>
                                <th>Risk Score</th>
                                <th>Risk Level</th>
                            </tr>
                        </thead>
                        <tbody>
                            {profiles.map(p => (
                                <tr
                                    key={p.customer_uuid}
                                    style={{ borderBottom: '1px solid #f1f1f1', cursor: 'pointer', transition: 'background 0.2s' }}
                                    onClick={() => navigate(`/investigate?cust_id=${p.customer_uuid}`)}
                                    onMouseOver={(e) => e.currentTarget.style.background = 'var(--light-red)'}
                                    onMouseOut={(e) => e.currentTarget.style.background = 'transparent'}
                                >
                                    <td style={{ padding: '16px 8px' }}>
                                        <div style={{ fontWeight: 700, fontSize: '14px', color: 'var(--pri-red)' }}>{p.full_name}</div>
                                        <div style={{ fontSize: '11px', color: '#888', fontFamily: 'monospace' }}>{p.upi_id}</div>
                                    </td>
                                    <td style={{ fontSize: '13px' }}>{p.bank_name}</td>
                                    <td style={{ fontSize: '13px' }}>≡ƒôì {p.primary_location}</td>
                                    <td style={{ fontWeight: 600 }}>{formatCurrency(p.total_amount)}</td>
                                    <td style={{ fontWeight: 700, color: p.anomaly_count > 0 ? '#ef4444' : '#22c55e' }}>{p.anomaly_count}</td>
                                    <td>
                                        <div style={{ fontWeight: 700, fontSize: '13px' }}>{p.risk_score} / 10</div>
                                    </td>
                                    <td>
                                        <span style={{
                                            padding: '4px 8px', fontSize: '10px', fontWeight: 700, borderRadius: '4px',
                                            background: p.risk_level === 'CRITICAL' ? '#fef2f2' : p.risk_level === 'HIGH' ? '#fff7ed' : '#f0fdf4',
                                            color: p.risk_level === 'CRITICAL' ? '#ef4444' : p.risk_level === 'HIGH' ? '#f97316' : '#22c55e'
                                        }}>
                                            {p.risk_level}
                                        </span>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                )}
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { ShieldAlert, ArrowLeft, Mail, FileDown, CheckCircle, AlertTriangle } from 'lucide-react';

export default function Investigate() {
    const [searchParams] = useSearchParams();
    const custId = searchParams.get('cust_id');
    const navigate = useNavigate();

    const [data, setData] = useState(null);
    const [loading, setLoading] = useState(true);
    const [sendingAlert, setSendingAlert] = useState(false);

    useEffect(() => {
        if (!custId) {
            setLoading(false);
            return;
        }

        axios.get(`/api/investigate/customer/${custId}`)
            .then(res => {
                setData(res.data);
                setLoading(false);
            })
            .catch(err => {
                console.error(err);
                setLoading(false);
            });
    }, [custId]);

    const downloadReport = async () => {
        try {
            const res = await axios.get(`/api/generate_customer_report/${custId}`, { responseType: 'blob' });
            const url = window.URL.createObjectURL(new Blob([res.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `Investigation_Report_${custId}.pdf`);
            document.body.appendChild(link);
            link.click();
            link.remove();
        } catch (e) {
            alert("Failed to generate PDF Report");
        }
    };

    const sendEmail = async () => {
        setSendingAlert(true);
        try {
            await axios.post('/api/send_customer_alert', { customer_uuid: custId });
            alert("Alert sent successfully to customer email.");
        } catch (e) {
            alert("Failed to send alert.");
        } finally {
            setSendingAlert(false);
        }
    };

    if (loading) return <div style={{ padding: '40px' }}>Loading investigation dossier...</div>;

    if (!custId || !data || data.error) return (
        <div style={{ padding: '40px' }}>
            <h1>Investigation Portal</h1>
            <p style={{ color: 'var(--text-dim)' }}>No customer selected. Please select a customer from the History tab.</p>
        </div>
    );

    const p = data.profile;
    const isCritical = p.risk_level === 'CRITICAL' || p.risk_level === 'HIGH';

    return (
        <div className="dashboard" style={{ paddingTop: '20px' }}>
            <button
                onClick={() => navigate('/history')}
                style={{ background: 'none', border: 'none', color: 'var(--pri-red)', display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer', marginBottom: '24px', fontWeight: 600, fontSize: '14px' }}>
                <ArrowLeft size={16} /> BACK TO HISTORY
            </button>

            <div style={{ display: 'flex', gap: '24px', marginBottom: '24px', alignItems: 'flex-start' }}>
                {/* Profile Info */}
                <div style={{ flex: 1, background: 'white', borderRadius: '12px', padding: '24px', border: '1px solid var(--light-red)' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                            <div style={{ width: '48px', height: '48px', borderRadius: '50%', background: 'var(--light-red)', color: 'var(--pri-red)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold', fontSize: '20px' }}>
                                {p.full_name.charAt(0)}
                            </div>
                            <div>
                                <h1 style={{ fontSize: '24px', color: 'var(--pri-red)', marginBottom: '4px' }}>{p.full_name}</h1>
                                <div style={{ fontFamily: 'monospace', fontSize: '11px', color: '#888' }}>{p.customer_uuid}</div>
                            </div>
                        </div>

                        <div style={{ textAlign: 'right' }}>
                            <div style={{ fontSize: '11px', color: '#888', textTransform: 'uppercase', marginBottom: '4px', letterSpacing: '1px' }}>Risk Assessment</div>
                            <div style={{
                                display: 'inline-flex', padding: '6px 12px', borderRadius: '6px', fontWeight: 'bold', fontSize: '14px', alignItems: 'center', gap: '6px',
                                background: isCritical ? '#fef2f2' : '#f0fdf4',
                                color: isCritical ? '#ef4444' : '#22c55e'
                            }}>
                                {isCritical ? <AlertTriangle size={16} /> : <CheckCircle size={16} />}
                                {p.risk_level} ΓÇó {p.risk_score} / 10
                            </div>
                        </div>
                    </div>

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', background: '#faf9f9', padding: '16px', borderRadius: '8px', fontSize: '13px' }}>
                        <div><span style={{ color: '#888' }}>UPI ID:</span> <span style={{ fontFamily: 'monospace', marginLeft: '8px' }}>{p.upi_id}</span></div>
                        <div><span style={{ color: '#888' }}>Bank:</span> <span style={{ marginLeft: '8px', fontWeight: 600 }}>{p.bank_name}</span></div>
                        <div><span style={{ color: '#888' }}>Account:</span> <span style={{ marginLeft: '8px' }}>{p.account_number}</span></div>
                        <div><span style={{ color: '#888' }}>Phone:</span> <span style={{ marginLeft: '8px' }}>{p.phone}</span></div>
                    </div>
                </div>

                {/* Actions Menu */}
                <div style={{ width: '300px', background: 'white', borderRadius: '12px', padding: '24px', border: '1px solid var(--light-red)' }}>
                    <h3 style={{ fontSize: '12px', textTransform: 'uppercase', color: '#888', letterSpacing: '1px', marginBottom: '16px' }}>Enforcement Actions</h3>

                    <button
                        onClick={sendEmail}
                        disabled={sendingAlert}
                        style={{ width: '100%', display: 'flex', alignItems: 'center', gap: '12px', padding: '14px', background: 'var(--pri-red)', color: 'white', border: 'none', borderRadius: '8px', fontWeight: 600, cursor: 'pointer', marginBottom: '12px' }}>
                        <Mail size={18} /> {sendingAlert ? "Sending..." : "Email Customer Alert"}
                    </button>

                    <button
                        onClick={downloadReport}
                        style={{ width: '100%', display: 'flex', alignItems: 'center', gap: '12px', padding: '14px', background: 'white', color: 'var(--text-dark)', border: '1px solid #ddd', borderRadius: '8px', fontWeight: 600, cursor: 'pointer' }}>
                        <FileDown size={18} /> Generate PDF Dossier
                    </button>
                </div>
            </div>

            {/* AI Report Section */}
            <div style={{ background: 'white', borderRadius: '12px', padding: '24px', border: '1px solid var(--light-red)', marginBottom: '24px' }}>
                <h3 style={{ display: 'flex', alignItems: 'center', gap: '8px', color: 'var(--pri-red)', borderBottom: '1px solid #eee', paddingBottom: '12px', marginBottom: '16px' }}>
                    <ShieldAlert size={20} /> AI Investigation Summary
                </h3>
                <div style={{ fontSize: '14px', lineHeight: '1.6', whiteSpace: 'pre-wrap', color: 'var(--text-dark)' }}>
                    {data.report_text.replace(/##/g, '').replace(/\*\*/g, '')}
                </div>
            </div>

        </div>
    );
}
